package agent

import (
	"context"
	"fmt"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/attemptmetrics"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
)

var durableAuditManagedPathspecs = []string{
	".ddx/beads.jsonl",
	".ddx/beads-archive.jsonl",
	".ddx/metrics/attempts.jsonl",
	".ddx/attachments",
}

type durableAuditBeadReader interface {
	Get(args ...any) (*bead.Bead, error)
}

// FinalizeDurableAttemptAudit appends the per-attempt metrics row, when the
// report carries an attempt_id, and commits any DDx-managed durable audit files
// that changed during the attempt.
func FinalizeDurableAttemptAudit(projectRoot string, store durableAuditBeadReader, report ExecuteBeadReport) error {
	if strings.TrimSpace(projectRoot) == "" {
		projectRoot = report.ProjectRoot
	}
	if strings.TrimSpace(projectRoot) == "" {
		return fmt.Errorf("finalize durable audit: project root required")
	}
	if strings.TrimSpace(report.AttemptID) != "" {
		if err := attemptmetrics.AppendRow(projectRoot, buildAttemptMetricsRow(store, report, time.Now().UTC())); err != nil {
			return fmt.Errorf("append attempt metrics: %w", err)
		}
	}
	if err := CommitDurableAuditOutputs(projectRoot, report.AttemptID); err != nil {
		return fmt.Errorf("commit durable audit outputs: %w", err)
	}
	return nil
}

// CommitDurableAuditOutputs stages and commits the DDx-managed durable audit
// paths when they are dirty. The commit is serialized through the main git lock
// so concurrent workers cannot interleave tracker and audit commits.
func CommitDurableAuditOutputs(projectRoot, attemptID string) error {
	return withTrackerLock(projectRoot, func() error {
		return commitDurableAuditOutputsLocked(projectRoot, attemptID)
	})
}

func buildAttemptMetricsRow(store durableAuditBeadReader, report ExecuteBeadReport, finishedAt time.Time) attemptmetrics.AttemptRow {
	specID := ""
	if report.BeadID != "" && store != nil {
		if b, err := store.Get(context.Background(), report.BeadID); err == nil && b != nil {
			specID, _ = b.Extra["spec-id"].(string)
		}
	}
	tsEnd := attemptmetrics.Rfc3339(finishedAt)
	tsStart := ""
	if report.DurationMS > 0 {
		start := finishedAt.Add(-time.Duration(report.DurationMS) * time.Millisecond)
		tsStart = attemptmetrics.Rfc3339(start)
	}
	return attemptmetrics.AttemptRow{
		SchemaVersion: attemptmetrics.SchemaVersion,
		AttemptID:     report.AttemptID,
		BeadID:        report.BeadID,
		SessionID:     report.SessionID,
		TSStart:       tsStart,
		TSEnd:         tsEnd,
		Model:         report.Model,
		Harness:       report.Harness,
		Profile:       report.RequestedProfile,
		Provider:      report.Provider,
		SpecID:        specID,
		Outcome:       report.Status,
		CostUSD:       report.CostUSD,
		DurationMS:    int(report.DurationMS),
		ReviewVerdict: report.ReviewVerdict,
	}
}

func commitDurableAuditOutputsLocked(projectRoot, attemptID string) error {
	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

	gitDir, managedPathspecs := ddxStateGitScope(projectRoot, durableAuditManagedPathspecs...)

	out, err := internalgit.Command(ctx, gitDir, "rev-parse", "--is-inside-work-tree").Output()
	if err != nil || strings.TrimSpace(string(out)) != "true" {
		return nil
	}

	statusArgs := []string{"status", "--short", "--untracked-files=all", "--"}
	statusArgs = append(statusArgs, managedPathspecs...)
	statusOut, err := internalgit.Command(ctx, gitDir, statusArgs...).Output()
	if err != nil {
		return fmt.Errorf("checking durable audit status: %w", err)
	}
	dirtyPaths := dirtyDurableAuditPaths(string(statusOut))
	if len(dirtyPaths) == 0 {
		return nil
	}

	addArgs := []string{"add", "-A", "--"}
	addArgs = append(addArgs, dirtyPaths...)
	addOut, err := runGitWithIndexLockRecovery(ctx, gitDir, addArgs...)
	if err != nil {
		return fmt.Errorf("staging durable audit outputs: %s: %w", strings.TrimSpace(string(addOut)), err)
	}

	cachedArgs := []string{"diff", "--cached", "--"}
	cachedArgs = append(cachedArgs, dirtyPaths...)
	if cached, err := internalgit.Command(ctx, gitDir, cachedArgs...).Output(); err == nil && strings.TrimSpace(string(cached)) == "" {
		return nil
	}

	commitArgs := []string{"commit", "--no-verify", "--only", "-m", durableAuditCommitMessage(attemptID), "--"}
	commitArgs = append(commitArgs, dirtyPaths...)
	commitArgs = ddxStateCommitArgs(projectRoot, gitDir, commitArgs...)
	commitOut, err := runGitWithIndexLockRecovery(ctx, gitDir, commitArgs...)
	if err != nil {
		return fmt.Errorf("committing durable audit outputs: %s: %w", strings.TrimSpace(string(commitOut)), err)
	}
	return nil
}

func dirtyDurableAuditPaths(statusOutput string) []string {
	lines := strings.Split(statusOutput, "\n")
	seen := make(map[string]struct{}, len(lines))
	paths := make([]string, 0, len(lines))
	for _, line := range lines {
		if len(line) < 4 {
			continue
		}
		path := strings.TrimSpace(line[3:])
		if arrow := strings.LastIndex(path, " -> "); arrow >= 0 {
			path = strings.TrimSpace(path[arrow+4:])
		}
		if path == "" {
			continue
		}
		if _, ok := seen[path]; ok {
			continue
		}
		seen[path] = struct{}{}
		paths = append(paths, path)
	}
	return paths
}

func durableAuditCommitMessage(attemptID string) string {
	id := strings.TrimSpace(attemptID)
	if id == "" {
		id = time.Now().UTC().Format("20060102T150405")
	}
	return fmt.Sprintf("chore: update tracker (execute-bead %s)", id)
}

package agent

import (
	"context"
	"fmt"
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
	"github.com/DocumentDrivenDX/ddx/internal/lockmetrics"
)

// LockRetryPolicy describes the retry/backoff curve used when attempting to
// acquire a process-shared lock that guards git index operations on the
// primary .git (the tracker-commit lock). The policy is owned by this
// package per ddx-da11a34a AC#4: callers in cli/internal/triage and
// elsewhere consult ActionRetryWithBackoff but do not duplicate the curve
// implementation here.
//
// The curve is exponential with a cap and a bounded max-retries budget so
// that lock contention is absorbed silently up to a point, after which it
// surfaces as an ordinary error to the caller. Per TD-031 §8.5
// (LockContentionContract) lock contention does NOT change persisted bead
// status; the bead remains claimable and the worker remains `draining`.
type LockRetryPolicy struct {
	// InitialBackoff is the wait before the second attempt.
	InitialBackoff time.Duration
	// MaxBackoff caps the per-step backoff after exponential growth.
	MaxBackoff time.Duration
	// Multiplier is the per-step growth factor (>= 1.0).
	Multiplier float64
	// MaxRetries bounds the number of acquisition attempts after the
	// initial try. Total attempts = MaxRetries + 1.
	MaxRetries int
	// MaxElapsed bounds the total wall-clock time spent retrying. If both
	// MaxRetries and MaxElapsed are set, the first to trip wins.
	MaxElapsed time.Duration
}

// DefaultLockRetryPolicy returns the policy used by withTrackerLock. The
// curve is intentionally tight (sub-second) for in-process tracker-commit
// contention; the larger 30s/90s/300s curve referenced by the auto-triage
// child of ddx-3c154349 lives one layer up, in cli/internal/triage —
// it consults ActionRetryWithBackoff and re-queues across drain passes,
// while this policy resolves contention within a single attempt.
func DefaultLockRetryPolicy() LockRetryPolicy {
	return LockRetryPolicy{
		InitialBackoff: 50 * time.Millisecond,
		MaxBackoff:     1 * time.Second,
		Multiplier:     2.0,
		MaxRetries:     200,
		MaxElapsed:     30 * time.Second,
	}
}

// step returns the backoff duration for retry index n (0-based: n=0 is the
// wait BEFORE the second acquisition attempt).
func (p LockRetryPolicy) step(n int) time.Duration {
	if p.InitialBackoff <= 0 {
		return 0
	}
	d := float64(p.InitialBackoff)
	m := p.Multiplier
	if m < 1 {
		m = 1
	}
	for i := 0; i < n; i++ {
		d *= m
		if p.MaxBackoff > 0 && d >= float64(p.MaxBackoff) {
			d = float64(p.MaxBackoff)
			break
		}
	}
	out := time.Duration(d)
	if p.MaxBackoff > 0 && out > p.MaxBackoff {
		out = p.MaxBackoff
	}
	return out
}

// trackerLockStaleAge is the age after which a held tracker lock is
// considered stale (owner crashed mid-commit) and may be forcibly broken.
var trackerLockStaleAge = 10 * time.Minute

// trackerLockPolicy is the active retry policy for withTrackerLock.
// Tests may swap this out via the exported helpers below.
var trackerLockPolicy = DefaultLockRetryPolicy()

// trackerLockPath returns the main-git lock directory for the given project
// root. The historical name remains because tests and older comments refer to
// the tracker lock, but the lock now protects all primary-checkout git writes:
// tracker commits, pre-dispatch checkpoint/ref updates, and landing.
//
// The lock target must be shared across linked worktrees for the same repo, so
// we prefer the primary DDx workspace when one exists instead of the caller's
// checkout-local .ddx directory.
func trackerLockPath(projectRoot string) string {
	return filepath.Join(sharedMainGitLockRoot(projectRoot), ddxroot.DirName, ".git-tracker.lock")
}

// sharedMainGitLockRoot resolves the DDx state root that should own the
// process-shared main-git lock. Linked worktrees should converge on the same
// primary workspace when one is available; otherwise we fall back to the
// normal project-scoped DDx path so convention-root projects keep their
// existing behavior.
func sharedMainGitLockRoot(projectRoot string) string {
	if workspace := gitpkg.FindNearestDDxWorkspace(projectRoot); workspace != "" {
		if info, err := os.Stat(filepath.Join(workspace, ddxroot.DirName)); err == nil && info.IsDir() {
			return workspace
		}
	}
	return ddxroot.Path(context.Background(), projectRoot)
}

// withMainGitLock acquires the process-shared main-git lock for the
// given project root, runs fn, and releases the lock. The lock is a
// directory created via os.Mkdir (atomic across processes on POSIX and
// Windows) following the same pattern as cli/internal/bead/lock.go.
//
// Contention is handled per LockRetryPolicy: exponential backoff up to a
// bounded budget. Per TD-031 §8.5 the contention itself does not change
// bead status; on budget exhaustion the caller surfaces an ordinary
// execution_failed and triage decides next steps.
func withMainGitLock(projectRoot string, fn func() error) error {
	if projectRoot == "" {
		return fn()
	}
	return withTrackerLockPolicy(projectRoot, trackerLockPolicy, fn)
}

// WithMainGitLock exposes the process-shared main-git lock to sibling
// packages that need the same serialized add/commit boundary as execute-bead
// landing and pre-dispatch checkpointing.
func WithMainGitLock(projectRoot string, fn func() error) error {
	return withMainGitLock(projectRoot, fn)
}

// withTrackerLock is retained for existing tracker/pre-dispatch call sites. It
// uses the same process-shared lock as landing so separate ddx work processes
// cannot interleave commits, ref updates, and checkout sync in the main tree.
func withTrackerLock(projectRoot string, fn func() error) error {
	return withMainGitLock(projectRoot, fn)
}

// TrackerLockSample carries timing and contention metrics for one
// withTrackerLock / withMainGitLock acquire+release cycle.
type TrackerLockSample struct {
	LockDir string
	Wait    time.Duration // time from entry to lock acquisition
	Hold    time.Duration // time the callback held the lock
	Retries int           // number of sleep-and-retry iterations (0 = acquired on first try)
}

// TrackerLockMetricsSink is called after each successful tracker-lock
// acquire+release cycle. The zero value (nil) is a no-op. Tests may swap
// this to capture metrics.
var TrackerLockMetricsSink func(TrackerLockSample)

// trackerLockContendedAttemptHook is a test-only hook fired after each
// failed acquire attempt that has been classified as real lock contention
// (a directory exists at lockDir and the stale-owner path did not reclaim
// it). It is invoked just before the retry sleep with the zero-based
// attempt index. The zero value (nil) is a no-op.
//
// Tests use this hook to deterministically synchronise with the retry
// loop — e.g. release the held lock from the hook so the next attempt
// observes a non-zero retry count without relying on time.Sleep races.
var trackerLockContendedAttemptHook func(attempt int)

// withTrackerLockPolicy is the policy-parameterised form of
// withTrackerLock; exposed at package scope so tests can pin a specific
// curve.
func withTrackerLockPolicy(projectRoot string, policy LockRetryPolicy, fn func() error) error {
	lockDir := trackerLockPath(projectRoot)
	if err := os.MkdirAll(filepath.Dir(lockDir), 0o755); err != nil {
		return fmt.Errorf("tracker lock dir: %w", err)
	}

	start := time.Now()
	retries := 0
	for attempt := 0; ; attempt++ {
		err := os.Mkdir(lockDir, 0o755)
		if err == nil {
			_ = os.WriteFile(filepath.Join(lockDir, "pid"),
				[]byte(fmt.Sprintf("%d", os.Getpid())), 0o644)
			_ = os.WriteFile(filepath.Join(lockDir, "acquired_at"),
				[]byte(time.Now().UTC().Format(time.RFC3339)), 0o644)
			break
		}

		// Classify what exists at lockDir before deciding to sleep or fail.
		// Per TD-031 §8.5: only a confirmed lock directory enters retry/backoff;
		// malformed paths are operator diagnostics, not lock contention.
		info, statErr := os.Lstat(lockDir)
		if statErr != nil {
			if os.IsNotExist(statErr) {
				// Path disappeared between Mkdir and Lstat (race). Retry immediately.
				continue
			}
			return fmt.Errorf("tracker lock stat: %w", statErr)
		}

		switch {
		case info.Mode().IsDir():
			// Real lock directory. Apply existing stale-owner policy.
			if breakStaleTrackerLock(lockDir) {
				continue
			}
			if attempt >= policy.MaxRetries {
				return lockTimeoutError(lockDir, "max retries")
			}
			if policy.MaxElapsed > 0 && time.Since(start) >= policy.MaxElapsed {
				return lockTimeoutError(lockDir, "max elapsed")
			}
			retries++
			if hook := trackerLockContendedAttemptHook; hook != nil {
				hook(attempt)
			}
			time.Sleep(policy.step(attempt))

		case info.Mode().IsRegular():
			// Malformed: lock path must be a directory, not a regular file.
			if time.Since(info.ModTime()) > trackerLockStaleAge {
				// Stale regular file: remove with single-path removal and retry immediately.
				if rmErr := os.Remove(lockDir); rmErr != nil && !os.IsNotExist(rmErr) {
					return fmt.Errorf("tracker lock: remove malformed stale file %s: %w", lockDir, rmErr)
				}
				continue
			}
			return fmt.Errorf("tracker lock: malformed lock path %s is a regular file; a lock directory was expected — remove it manually to recover", lockDir)

		default:
			// Symlink, socket, device, or other special filesystem object. Do not remove.
			return fmt.Errorf("tracker lock: malformed lock path %s has type %v; a lock directory was expected — inspect and remove it manually to recover", lockDir, info.Mode().Type())
		}
	}

	waitDur := time.Since(start)
	holdStart := time.Now()
	defer os.RemoveAll(lockDir)
	fnErr := lockmetrics.Instrument("tracker.lock", "tracker.commit", fn)
	if sink := TrackerLockMetricsSink; sink != nil {
		sink(TrackerLockSample{LockDir: lockDir, Wait: waitDur, Hold: time.Since(holdStart), Retries: retries})
	}
	return fnErr
}

func lockTimeoutError(lockDir, why string) error {
	owner := "missing"
	if pidData, perr := os.ReadFile(filepath.Join(lockDir, "pid")); perr == nil && len(pidData) > 0 {
		owner = strings.TrimSpace(string(pidData))
	}
	return fmt.Errorf("tracker lock timeout (%s, lock: %s, owner pid: %s)", why, lockDir, owner)
}

// breakStaleTrackerLock removes lockDir if its owner process is dead or the
// lock is older than trackerLockStaleAge. Returns true if the lock was broken.
func breakStaleTrackerLock(lockDir string) bool {
	pidData, err := os.ReadFile(filepath.Join(lockDir, "pid"))
	if err == nil {
		pid, err := strconv.Atoi(strings.TrimSpace(string(pidData)))
		if err == nil && pid > 0 && pid != os.Getpid() {
			if !trackerProcessAlive(pid) {
				os.RemoveAll(lockDir)
				return true
			}
		}
	}

	acquiredData, err := os.ReadFile(filepath.Join(lockDir, "acquired_at"))
	if err == nil {
		acquired, err := time.Parse(time.RFC3339, strings.TrimSpace(string(acquiredData)))
		if err == nil && time.Since(acquired) > trackerLockStaleAge {
			os.RemoveAll(lockDir)
			return true
		}
	}

	return false
}

	message := "commit or clean the listed implementation files before restarting ddx work"
	if len(paths) > 0 {
		message = fmt.Sprintf("commit or clean the listed implementation files before restarting ddx work: %s", strings.Join(paths, ", "))
	}
	return &OperatorAttentionStop{
		Reason:      "checkpoint_dirty",
		BeadID:      beadID,
		ProjectRoot: projectRoot,
		DirtyPaths:  paths,
		Message:     message,
	}, true
}

func parsePreExecuteCheckpointDirtyPaths(detail string) []string {
	idx := strings.Index(detail, preDispatchCheckpointDirtyRefusalPrefix)
	if idx == -1 {
		return nil
	}
	pathsField := detail[idx+len(preDispatchCheckpointDirtyRefusalPrefix):]
	if semi := strings.Index(pathsField, ";"); semi >= 0 {
		pathsField = pathsField[:semi]
	}
	var paths []string
	for _, path := range strings.Split(pathsField, ",") {
		path = strings.TrimSpace(path)
		if path != "" {
			paths = append(paths, path)
		}
	}
	return paths
}

// isTransientGitContention reports git index/ref contention errors that are
// transient under concurrent workers and must be retried rather than treated
// as a worker-stopping failure (ddx-23ac2796 and its sibling variants). It
// covers .git/index.lock conflicts plus the "unable to write new index file"
// and "cannot lock ref" forms git emits when a concurrent process holds the
// index/ref. A persistent cause (e.g. ENOSPC) simply keeps releasing+retrying
// the bead, which is still preferable to halting the whole unattended drain.
func isTransientGitContention(msg string) bool {
	if gitlock.IsIndexLockError(msg) {
		return true
	}
	lower := strings.ToLower(msg)
	for _, marker := range []string{
		"unable to write new index file",
		"cannot lock ref",
		"unable to update the ref",
	} {
		if strings.Contains(lower, marker) {
			return true
		}
	}
	return false
}

func (w *ExecuteBeadWorker) Run(ctx context.Context, rcfg config.ResolvedConfig, runtime ExecuteBeadLoopRuntime) (*ExecuteBeadLoopResult, error) {
	if w.Store == nil {
		return nil, fmt.Errorf("execute-bead loop: store is required")
	}
	if w.Executor == nil {
		return nil, fmt.Errorf("execute-bead loop: executor is required")
	}

	now := w.Now
	if now == nil {
		now = time.Now
	}
	assignee := rcfg.Assignee()
	if assignee == "" {
		assignee = "ddx"
	}
	preClaimTimeout := runtime.PreClaimTimeout
	if preClaimTimeout <= 0 {
		preClaimTimeout = work.DefaultPreClaimTimeout
	}
	noProgressCooldown := rcfg.NoProgressCooldown()
	if noProgressCooldown <= 0 {
		noProgressCooldown = 6 * time.Hour
	}
	heartbeatInterval := rcfg.HeartbeatInterval()
	if heartbeatInterval <= 0 {
		heartbeatInterval = bead.HeartbeatInterval
	}
	harness := rcfg.Harness()
	provider := rcfg.Provider()
	model := rcfg.Model()
	profile := rcfg.Profile()
	loopMode, idleInterval := runtime.loopIntent()

	result := &ExecuteBeadLoopResult{}
	resultsResetIdx := 0
	transientCandidateSkips := map[string]string{}
	w.transientCandidateSkips = transientCandidateSkips
	defer func() {
		w.transientCandidateSkips = nil
	}()
	// pausedInfraUntil is set when a no_viable_provider outcome is recorded.
	// The worker sleeps until this time (in Watch mode) before re-evaluating
	// the queue, leaving all beads immediately reclaimable. Zero means no pause.
	var pausedInfraUntil time.Time
	complexityGuard := work.NewComplexityGuard(w.ComplexityGate, runtime.Log)
	preclaimGuard := work.NewPreClaimGuard(runtime.PreClaimHook, w.Store, runtime.Log, now, 30*time.Second, preClaimTimeout)
	workLog := NewWorkLogRenderer(WorkLogRendererOptions{Now: now})
	wasIdle := false
	lastIdleQueueSignature := ""

	// Pre-claim idle escalation state (ddx-df77e668 AC #3). When the worker
	// idles on the same pre-claim blocker for preClaimIdleEscalationThreshold
	// consecutive cycles, it emits a non-terminal operator-attention event so
	// the stall is visible instead of looping silently. The streak resets when
	// the blocker detail changes or the worker stops idling on it.
	preClaimIdleDetail := ""
	preClaimIdleStreak := 0
	preClaimIdleFirstAt := time.Time{}
	preClaimIdleEscalated := false
	resetPreClaimIdleStreak := func() {
		preClaimIdleDetail = ""
		preClaimIdleStreak = 0
		preClaimIdleEscalated = false
	}

	// Worker-side liveness sidecar. Updated on each heartbeat tick so an
	// operator's `ddx work focus` / GraphQL panel can answer "is this worker
	// alive and what is it doing?" without paying tracker rewrite cost. The
	// sidecar is best-effort: write/sink failures do not interrupt the loop.
	// The reporter is constructed here but does NOT emit until a bead is
	// claimed — that order keeps loop.start as the first envelope on the
	// EventSink so structured-event consumers continue to see it.
	var liveness *work.SidecarLivenessReporter
	if runtime.ProjectRoot != "" && runtime.SessionID != "" {
		liveness = work.NewSidecarLivenessReporter(runtime.ProjectRoot, runtime.SessionID, runtime.SessionID, runtime.EventSink)
	}

	emit := func(eventType string, data map[string]any) {
		writeLoopEvent(runtime.EventSink, runtime.SessionID, eventType, data, now().UTC())
	}
	claimSuccessRateWindowSize := runtime.effectiveClaimSuccessRateWindow()
	claimSuccessRateThreshold := runtime.effectiveClaimSuccessRateThreshold()
	claimSuccessRateWindow := make([]bool, 0, claimSuccessRateWindowSize)
	claimSuccessRateSuccesses := 0
	claimSuccessRateWarned := false
	preClaimWarnThreshold := runtime.effectivePreClaimWarnRepeatThreshold()
	preClaimWarnState := preClaimWarnRepeatState{}
	// exitReason is populated as the loop exits to surface a structured reason
	// in the loop.end event (ddx-dc157075 AC #4). Work-owned terminal reasons
	// are classified through work.StopCondition; fatal_config,
	// preflight_failed, resource_exhausted, and future provider exhaustion are
	// still subsystem-specific exits.
	exitReason := ""
	setExit := func(condition, reason string) {
		exitReason = reason
		result.StopCondition = condition
		result.ExitReason = reason
	}
	appendPreClaimWarn := func(beadID, reason, detail string, at time.Time) bool {
		escalated := appendPreClaimIntakeWarning(w.Store, emit, &preClaimWarnState, preClaimWarnThreshold, beadID, assignee, reason, detail, at)
		if !escalated {
			return false
		}
		detailText := fmt.Sprintf(
			"pre-claim warn fingerprint repeated %d times across %d distinct bead IDs",
			preClaimWarnState.Count,
			len(preClaimWarnState.DistinctBeadIDs),
		)
		result.OperatorAttention = &OperatorAttentionStop{
			Reason:      "preclaim_warn_repeated",
			BeadID:      beadID,
			ProjectRoot: runtime.ProjectRoot,
			Message:     detailText,
		}
		setExit("OperatorAttention", "operator_attention")
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "operator attention: %s\n", detailText)
		}
		return true
	}
	recordClaimAttempt := func(success bool, beadID string) {
		if claimSuccessRateWindowSize <= 0 {
			return
		}
		if len(claimSuccessRateWindow) == claimSuccessRateWindowSize {
			if claimSuccessRateWindow[0] {
				claimSuccessRateSuccesses--
			}
			copy(claimSuccessRateWindow, claimSuccessRateWindow[1:])
			claimSuccessRateWindow = claimSuccessRateWindow[:claimSuccessRateWindowSize-1]
		}
		claimSuccessRateWindow = append(claimSuccessRateWindow, success)
		if success {
			claimSuccessRateSuccesses++
			claimSuccessRateWarned = false
			return
		}
		if len(claimSuccessRateWindow) < claimSuccessRateWindowSize {
			return
		}
		rate := float64(claimSuccessRateSuccesses) / float64(claimSuccessRateWindowSize)
		if rate > claimSuccessRateThreshold || claimSuccessRateWarned {
			return
		}
		claimSuccessRateWarned = true
		detail := fmt.Sprintf(
			"claim success rate %.3f over the last %d claim attempts (%d successes, %d non-successes) is at or below threshold %.3f; manual intervention may be required",
			rate,
			claimSuccessRateWindowSize,
			claimSuccessRateSuccesses,
			claimSuccessRateWindowSize-claimSuccessRateSuccesses,
