+// ErrTrackerLockTimeout marks a bounded tracker/main-git lock acquisition
+// timeout. Callers use errors.Is so ordinary fmt.Errorf("%w") wrapping keeps
+// the contention class stable.
+var ErrTrackerLockTimeout = errors.New("tracker lock timeout")
+
+// TrackerLockTimeoutError reports a bounded wait on the DDx main-git lock.
+// The string form is intentionally unchanged because older callers and logs
+// classify historical diagnostics by substring.
+type TrackerLockTimeoutError struct {
+	Why      string
+	LockDir  string
+	OwnerPID string
+}
+
+func (e *TrackerLockTimeoutError) Error() string {
+	if e == nil {
+		return ErrTrackerLockTimeout.Error()
+	}
+	owner := strings.TrimSpace(e.OwnerPID)
+	if owner == "" {
+		owner = "missing"
+	}
+	return fmt.Sprintf("tracker lock timeout (%s, lock: %s, owner pid: %s)", e.Why, e.LockDir, owner)
+}
+
+func (e *TrackerLockTimeoutError) Is(target error) bool {
+	return target == ErrTrackerLockTimeout
+}
+
+func IsTrackerLockTimeout(err error) bool {
+	return errors.Is(err, ErrTrackerLockTimeout)
+}
